import { execution } from '@dynatrace-sdk/automation-utils';
import { metricsClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    const timeFrameMs = parseInt(input.timeFrameMinutes || 60) * 60 * 1000;
    const from = Date.now() - timeFrameMs;
    const to = Date.now();
    const resolution = parseInt(input.resolutionSeconds || 60) * 1000;

    const response = await metricsClient.queryMetricsData({
      metricSelector: input.metricSelector,
      entities: [input.entityId],
      from: from,
      to: to,
      resolution: `${resolution}ms`
    });

    const results = response.result || [];
    const firstResult = results[0] || {};
    const data = firstResult.data || [];

    let stats = {
      dataPoints: data.length,
      min: null,
      max: null,
      avg: null
    };

    if (data.length > 0) {
      const values = data.map(d => d.values[0]).filter(v => v !== null);
      if (values.length > 0) {
        stats.min = Math.min(...values);
        stats.max = Math.max(...values);
        stats.avg = (values.reduce((a, b) => a + b, 0) / values.length).toFixed(2);
      }
    }

    console.log(`Retrieved ${data.length} metric data points`);

    return {
      entityId: input.entityId,
      metricSelector: input.metricSelector,
      statistics: stats,
      timeFrame: input.timeFrameMinutes,
      resolution: input.resolutionSeconds,
      dataPoints: data.slice(0, 10).map((d, idx) => ({
        timestamp: new Date(d.timestamp).toISOString(),
        value: d.values[0]
      }))
    };
  } catch (error) {
    console.error('Error querying metrics:', error);
    throw new Error(`Failed to query metrics: ${error}`);
  }
}
